app.service("SongsService",function($http,$q){this.getVisibleSongLists=function(){return $q.all({lists:$http.post("/ajax",{command:"get_all_song_lists"}),settings:$http.post("/ajax",{command:"get_user_settings"})}).then(function(results){var allLists=results.lists.data||[],settings=results.settings.data;return settings&&settings.available_lists?settings.available_lists.split(",").map(function(id){return id.trim()}).map(function(id){for(var i=0;i<allLists.length;i++)if(String(allLists[i].LIST_ID)===id)return allLists[i];return null}).filter(Boolean):allLists})},this.getSongsForSearch=function(listIds){return listIds&&listIds.length?$http.post("/ajax",{command:"get_songs_for_search",list_ids:listIds.join(",")}).then(function(r){return r.data||[]}):$q.resolve([])},this.getLanguages=function(){return $http.post("/ajax",{command:"get_languages"}).then(function(r){return r.data||[]})}});